// Process request from host to do tensor reshape/resize

void kernel_copy_exe(
   unsigned int _req_id,
   unsigned int _input,
   unsigned int _output,
   int _w,
   int _h,
   int _src_channel_fmt,
   int _src_channel_color,
   int _dst_channel_fmt,
   int _dst_channel_color,
   int _src_w,
   int _src_h,
   int _x_off,
   int _y_off,
   int _dst_x,
   int _dst_y,
   int _dst_w,
   int _dst_h,
   unsigned int _equalize)
{
   RequestCopy req;

   ztaInitPcore(zta_pcore_img);
   ztaInitStream(_equalize);
      
   req.input=_input;
   req.output=_output;
   req.w=_w;
   req.h=_h;
   req.src_channel_fmt=_src_channel_fmt;
   req.src_channel_color=_src_channel_color;
   req.dst_channel_fmt=_dst_channel_fmt;
   req.dst_channel_color=_dst_channel_color;
   req.src_w=_src_w;
   req.src_h=_src_h;
   req.x_off=_x_off;
   req.y_off=_y_off;
   req.dst_x=_dst_x;
   req.dst_y=_dst_y;
   req.dst_w=_dst_w;
   req.dst_h=_dst_h;
   req.equalize=_equalize;
   ztaDualHartExecute(copy,&req);
   ztaJobDone(_req_id);
}

// Process request from host to do YUYV to RGB color conversion

void kernel_yuyv2rgb_exe(
   unsigned int _req_id,
   unsigned int _input,
   unsigned int _output,
   unsigned int _spu,
   int _w,
   int _h,
   int _dst_channel_fmt,
   int _dst_channel_color,   
   int _src_w,
   int _src_h,
   int _x_off,
   int _y_off,
   int _dst_x,
   int _dst_y,
   int _dst_w,
   int _dst_h
) {
   RequestColor req;

   ztaInitPcore(zta_pcore_img);
   ztaInitStream(_spu);
      
   req.input=_input;
   req.output=_output;
   req.spu=_spu;
   req.w=_w;
   req.h=_h;
   req.dst_channel_fmt=_dst_channel_fmt;
   req.dst_channel_color=_dst_channel_color;
   req.src_w=_src_w;
   req.src_h=_src_h;
   req.x_off=_x_off;
   req.y_off=_y_off;
   req.dst_x=_dst_x;
   req.dst_y=_dst_y;
   req.dst_w=_dst_w;
   req.dst_h=_dst_h;
   
   ztaDualHartExecute(yuyv2rgb,&req);
      
   ztaJobDone(_req_id);
}
